#!/usr/bin/env python3
"""PreToolUse hook: protect sensitive and auto-generated files from Write/Edit.

Reads Claude Code hook JSON from stdin. Outputs block decision or exits 0 (allow).
"""
import sys
import os
import json
import re

def block(reason):
    print(json.dumps({"decision": "block", "reason": reason}))
    sys.exit(0)

def main():
    try:
        data = json.load(sys.stdin)
    except json.JSONDecodeError:
        sys.exit(0)

    file_path = data.get("tool_input", {}).get("file_path", "")
    if not file_path:
        sys.exit(0)

    basename = os.path.basename(file_path)
    root = os.path.dirname(os.path.dirname(os.path.dirname(os.path.abspath(__file__))))
    
    # Try to get relative path, if it fails, fallback to file_path
    try:
        rel_path = os.path.relpath(file_path, root)
    except ValueError:
        rel_path = file_path

    # Convert windows separators to posix for easier matching
    rel_path_posix = rel_path.replace("\\", "/")

    # ── Environment files (secrets) ──────────────────────────────────────────────
    if basename == ".env" or basename.startswith(".env."):
        block(f"Protected file: {basename}. Environment files may contain secrets.")

    # ── Git internals ────────────────────────────────────────────────────────────
    if re.search(r"^\.git/|/\.git/", rel_path_posix):
        block("Protected path: .git/ internals must not be modified by agents.")

    # ── Auto-generated workspace files ───────────────────────────────────────────
    if rel_path_posix in ["WORKSPACE.md", "mAIcelium.code-workspace"]:
        block(f"Protected file: {rel_path_posix} is auto-generated. Use bin/ scripts to modify it.")
        
    if rel_path_posix == ".claude/projects-context.md":
        block("Protected file: projects-context.md is auto-generated by sync_symlinks scripts.")

    # ── Agent config (prevent self-modification of permissions) ──────────────────
    if rel_path_posix in [".claude/settings.json", ".claude/settings.local.json"]:
        block(f"Protected file: {rel_path_posix}. Agent must not modify its own permissions.")

    # ── Auto-generated IDE dotfolders ────────────────────────────────────────────
    if re.search(r"^\.(cursor|agents|antigravity)/", rel_path_posix):
        block(f"Protected path: {rel_path_posix} is auto-generated via symlinks. Write to mesh/ instead.")

    # ── Lockfiles ────────────────────────────────────────────────────────────────
    if basename in ["package-lock.json", "yarn.lock", "pnpm-lock.yaml", "poetry.lock", "Pipfile.lock"]:
        block(f"Protected file: {basename} is a lockfile. Use the package manager to update it.")

    # All checks passed — allow silently
    sys.exit(0)

if __name__ == "__main__":
    main()
